import requests

# List of news sources and their respective endpoints
news_sources = {
    'Google News': 'https://newsapi.org/v2/top-headlines?apiKey=YOUR_API_KEY&sources=google-news',
    'The Hindu': 'https://api.thehindu.com/news/feeder.json?apiKey=YOUR_API_KEY',
    'Economic Times': 'https://economictimes.indiatimes.com/news.cms?feedtype=sjson&apikeY=YOUR_API_KEY',
    # Add More Sources as Required
}

def fetch_news(api_urls):
    news_articles = []
    for source, url in api_urls.items():
        response = requests.get(url)
        data = response.json()
        if data["status"] == "ok":
            articles = data["articles"]
            for article in articles:
                structured_article = {
                    'title': article['title'],
                    'description': article['description'],
                    'link': article['url'],
                    'published': article['publishedAt']
                }
                news_articles.append(structured_article)
    return news_articles

# Fetching and Structuring News
articles = fetch_news(news_sources)
if articles:
    for article in articles:
        # Displaying the fetched and structured articles
        print(article)

